#include<cstdio>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline void chkmax(T&x,const T&w){x<w?x=w:T();}
const int N=1e5+10,W=1e5;int a[N],dp[N],t[N],n,P[N],mx[N],mn[N];
inline void add(int p,const int &w){while(p<=W)chkmax(t[p],w),p+=(p&-p);}
inline void del(int p){while(p<=W)t[p]=0,p+=(p&-p);}
inline int qry(int p){int res(0);while(p)chkmax(res,t[p]),p^=(p&-p);return res;}
inline bool cmpMx(const int &x,const int &y){return mx[x]<mx[y];}
inline bool cmpA(const int &x,const int &y){return a[x]<a[y];}
inline void cdq(const int &l,const int &r)
{
	
	if(l==r)return chkmax(dp[l],1);std::sort(P+l,P+r+1);int mid=(l+r)>>1;
	
	cdq(l,mid);std::sort(P+l,P+mid+1,cmpMx);std::sort(P+mid+1,P+r+1,cmpA);
	int pl=l,pr=mid+1;while(pr<=r)
	{
		while(pl<=mid&&mx[P[pl]]<=a[P[pr]])add(a[P[pl]],dp[P[pl]]),++pl;
		chkmax(dp[P[pr]],qry(mn[P[pr]])+1);++pr;
	}
	for(int i=l;i<pl;++i)del(a[P[i]]);cdq(mid+1,r);
}
int main()
{
	memset(mn,0x3f,sizeof(mn));n=read();int m=read();rep(1,n,i)mn[i]=mx[i]=a[i]=read(),P[i]=i;
	while(m--){int x=read(),w=read();chkmax(mx[x],w);w<mn[x]?mn[x]=w:0;} cdq(1,n);
	int ans=0;rep(1,n,i)chkmax(ans,dp[i]); printf("%d\n",ans);return 0;
}
